-- Shopping Behavior Analysis - SQL Script
-- Author: Gaurav

SELECT * FROM SHOPPING_TABLE;

-- Q1. Total revenue generated by male and female customers
SELECT 
    GENDER, 
    SUM(PURCHASE_AMOUNT) AS TOTAL_REVENUE
FROM 
    SHOPPING_TABLE
GROUP BY GENDER;

-- Q2. Customers who used a discount but still spent more than average
SELECT 
    CUSTOMER_ID, 
    PURCHASE_AMOUNT
FROM 
    SHOPPING_TABLE
WHERE 
    DISCOUNT_APPLIED = 'Yes' -- Ensure this matches your data (Yes/YES)
    AND PURCHASE_AMOUNT >= (SELECT AVG(PURCHASE_AMOUNT) FROM SHOPPING_TABLE);

-- Q3. Top 5 products with highest average review rating
SELECT 
    ITEM_PURCHASED AS PRODUCT,
    ROUND(AVG(REVIEW_RATING), 2) AS AVG_REVIEW_RATING
FROM 
    SHOPPING_TABLE
GROUP BY PRODUCT
ORDER BY AVG_REVIEW_RATING DESC
LIMIT 5;
    
-- Q4. Average purchase amounts between Standard and Express shipping    
SELECT 
    SHIPPING_TYPE,
    ROUND(AVG(PURCHASE_AMOUNT), 2) AS AVERAGE_PURCHASE_AMOUNT
FROM 
    SHOPPING_TABLE
WHERE 
    SHIPPING_TYPE IN ('Standard', 'Express')
GROUP BY SHIPPING_TYPE;

-- Q5. Subscription Spend Analysis (Subscribers vs Non-subscribers)
SELECT 
    SUBSCRIPTION_STATUS,
    COUNT(CUSTOMER_ID) AS TOTAL_CUSTOMERS,
    ROUND(SUM(PURCHASE_AMOUNT), 2) AS TOTAL_REVENUE,
    ROUND(AVG(PURCHASE_AMOUNT), 2) AS AVG_SPEND
FROM 
    SHOPPING_TABLE
GROUP BY SUBSCRIPTION_STATUS;

-- Q6. Top 5 Products with highest discount application rate (%)
SELECT 
    ITEM_PURCHASED,
    ROUND(SUM(CASE WHEN DISCOUNT_APPLIED = 'Yes' THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 2) AS DISCOUNT_RATE
FROM 
    SHOPPING_TABLE
GROUP BY ITEM_PURCHASED
ORDER BY DISCOUNT_RATE DESC
LIMIT 5;

-- Q7. Customer Segmentation (New, Returning, Loyal)
WITH CUSTOMER_TYPE AS (
    SELECT CUSTOMER_ID, PREVIOUS_PURCHASES, 
    CASE 
        WHEN PREVIOUS_PURCHASES = 1 THEN 'New'
        WHEN PREVIOUS_PURCHASES BETWEEN 2 AND 10 THEN 'Returning'
        ELSE 'Loyal' 
    END AS CUSTOMER_SEGMENT
    FROM SHOPPING_TABLE
)
SELECT CUSTOMER_SEGMENT, COUNT(*) AS NUMBER_OF_CUSTOMERS
FROM CUSTOMER_TYPE
GROUP BY CUSTOMER_SEGMENT;

-- Q8. Top 3 most purchased products within each category
WITH ITEM_COUNTS AS (
    SELECT 
        CATEGORY,
        ITEM_PURCHASED, 
        COUNT(CUSTOMER_ID) AS TOTAL_ORDERS,
        ROW_NUMBER() OVER (PARTITION BY CATEGORY ORDER BY COUNT(CUSTOMER_ID) DESC) AS ITEM_RANK
    FROM SHOPPING_TABLE
    GROUP BY CATEGORY, ITEM_PURCHASED
) 
SELECT ITEM_RANK, CATEGORY, ITEM_PURCHASED, TOTAL_ORDERS
FROM ITEM_COUNTS
WHERE ITEM_RANK <= 3;

-- Q9. Subscription likelihood of repeat buyers (> 5 purchases)
SELECT 
    SUBSCRIPTION_STATUS, 
    COUNT(CUSTOMER_ID) AS REPEAT_BUYERS
FROM 
    SHOPPING_TABLE
WHERE 
    PREVIOUS_PURCHASES > 5
GROUP BY SUBSCRIPTION_STATUS;

-- Q10. Revenue contribution by Age Group
SELECT 
    AGE_GROUP, 
    SUM(PURCHASE_AMOUNT) AS REVENUE
FROM 
    SHOPPING_TABLE
GROUP BY AGE_GROUP
ORDER BY REVENUE DESC;